def get_input():
    h, w = map(float, input().split())
    return h, w

def calc_bmi(h, w):
    return w / (h * h)

def classify(bmi):
    if bmi < 18.5:
        return "저체중"
    elif bmi < 23:
        return "정상"
    elif bmi < 25:
        return "과체중"
    else:
        return "비만"

h, w = get_input()
bmi = calc_bmi(h, w)
print(f"BMI: {bmi:.2f} ({classify(bmi)})")

def count_o1(n):
    return 1  # 입력 크기 n과 무관 -> O(1)

def count_ologn(n):
    count = 0
    while n > 1:
        n //= 2  # 절반씩 줄어든다 -> O(log N)
        count += 1
    return count

def count_on(n):
    count = 0
    for i in range(n):  # n번 반복 -> O(N)
        count += 1
    return count

def count_onlogn(n):
    count = 0
    m = n
    while m > 1:  # log N번 절반씩 줄고
        for i in range(n):  # 그때마다 n번 반복 -> O(N log N)
            count += 1
        m //= 2
    return count

def count_on2(n):
    count = 0
    for i in range(n):
        for j in range(n):  # 이중 반복 -> O(N^2)
            count += 1
    return count

def count_o2n(n):
    count = 0
    def helper(k):
        nonlocal count
        count += 1
        if k <= 0:
            return
        helper(k - 1)  # 재귀가 2갈래로 -> O(2^N)
        helper(k - 1)
    helper(n)
    return count

for n in [4, 8, 16]:
    print("N =", n)
    print("  O(1)      :", count_o1(n))
    print("  O(log N)  :", count_ologn(n))
    print("  O(N)      :", count_on(n))
    print("  O(N log N):", count_onlogn(n))
    print("  O(N^2)    :", count_on2(n))
    print("  O(2^N)    :", count_o2n(n))
